// ── Deep merge for partial language overrides ────────────────────────────
type AnyObj = Record<string, unknown>
export function deepAssign<T extends AnyObj>(base: T, over: AnyObj): T {
  const out = { ...base }
  for (const k of Object.keys(over)) {
    const v = over[k]; const b = (base as AnyObj)[k]
    if (v && b && typeof v === 'object' && typeof b === 'object' && !Array.isArray(v)) {
      (out as AnyObj)[k] = deepAssign(b as AnyObj, v as AnyObj)
    } else if (v !== undefined) { (out as AnyObj)[k] = v }
  }
  return out
}

