export type T = typeof translations.en
export function useT(lang: Lang): T {
  const full = (translations as Record<string, unknown>)[lang]
  if (full) return full as T
  const ui = LANG_UI[lang]
  if (ui) return deepAssign({ ...translations.en } as AnyObj, ui) as T
  return translations.en
}

// Devuelve la traducción completamente resuelta para un locale (igual que useT,
// pero sin el hook de React) — aplica el fallback parcial sobre inglés cuando
// el locale solo tiene textos de UI (LANG_UI) y no contenido completo.
export function resolveLocale(lang: string): T {
  const full = (translations as Record<string, unknown>)[lang]
  if (full) return full as T
  const ui = LANG_UI[lang]
  if (ui) return deepAssign({ ...translations.en } as AnyObj, ui) as T
  return translations.en
}
